void generatePattern(const vector<int>& primes, int size) {
    vector<int> pattern(size, 0);
    int primeIndex = 0;
    for (int i = 0; i < size; ++i) {
        if (primeIndex < primes.size() && i % primes[primeIndex] == 0) {
            pattern[i] = primes[primeIndex];
            ++primeIndex;
        } else {
            pattern[i] = i + 1;
        }
    }
    for (int val : pattern) {
        cout << val << " ";
    }
    cout << endl;
}

